{
  "handoff_brief": {
    "recipient": "Shaq",
    "task_context": "Implement API rate limiting middleware. Four agents have aligned on requirements, architecture, operational concerns, and risk areas. One design correction was surfaced during review: the original fixed-window approach was upgraded to a true sliding window to match the domain requirement of a rolling window. This brief gives you everything needed to implement.",
    "domain_rules": [
      {
        "rule": "Rate limit is 100 requests per 60-second rolling window per API key",
        "testable_assertion": "Given a single API key, sending 101 requests within any 60-second sliding window results in the 101st being rejected with HTTP 429"
      },
      {
        "rule": "Exceeded limit returns HTTP 429 with Retry-After header",
        "testable_assertion": "The Retry-After header value is the number of seconds until enough requests expire from the sliding window to allow a new one — not a fixed value"
      },
      {
        "rule": "Window resets on a rolling basis as old requests age out",
        "testable_assertion": "After the oldest request in the window is more than 60 seconds old, it no longer counts toward the 100-request limit"
      },
      {
        "rule": "Rate limiter must fail open when Redis is unavailable",
        "testable_assertion": "If Redis is down, requests are allowed through and a redis_unavailable_total metric is incremented"
      }
    ],
    "architecture_guidance": [
      {
        "decision": "Use Redis sorted sets for a true sliding window (not fixed-window counters)",
        "implementation_note": "Use ZADD with the request timestamp as score, ZREMRANGEBYSCORE to prune entries older than 60s, and ZCARD to count. Key pattern: rate_limit:{api_key}. This avoids the boundary-burst problem that a fixed-window approach (bucketed by window_start_unix) would have. See Kobe's review for rationale."
      },
      {
        "decision": "Middleware runs before all authenticated routes",
        "implementation_note": "Place the rate limit check after authentication (so you have the API key) but before any business logic. Extract the API key from the auth context, not from a raw header."
      },
      {
        "decision": "Retry-After is dynamically computed from the sorted set",
        "implementation_note": "Compute as: 60 - (now - oldest_request_timestamp_in_window). This tells the caller exactly when the earliest slot frees up. Use ZRANGE to get the oldest entry's score."
      },
      {
        "decision": "Fail-open on Redis failure",
        "implementation_note": "Wrap all Redis calls in try/catch. On any Redis error, log it, increment redis_unavailable_total, and allow the request through. Do NOT throw or return 500."
      }
    ],
    "acceptance_criteria": [
      {
        "criterion": "101st request in a rolling 60s window is rejected",
        "given": "An API key has made 100 requests in the last 60 seconds",
        "when": "A 101st request arrives",
        "then": "HTTP 429 is returned with a Retry-After header whose value is the seconds until the oldest request ages out of the window"
      },
      {
        "criterion": "Rolling window resets correctly",
        "given": "An API key hit the limit and 60 seconds have passed since the first request in the window",
        "when": "A new request arrives after that oldest request has aged out",
        "then": "The request succeeds with HTTP 200 (or appropriate status)"
      },
      {
        "criterion": "No boundary burst with sliding window",
        "given": "An API key sends 99 requests at second 59 of one conceptual minute and 99 requests at second 0 of the next",
        "when": "The sliding window is evaluated",
        "then": "The second batch is correctly counted against the same window as the first, and requests beyond 100 total in any 60s span are rejected"
      },
      {
        "criterion": "Fail-open when Redis is unavailable",
        "given": "Redis is down or unreachable",
        "when": "Any request arrives",
        "then": "The request is allowed through, redis_unavailable_total is incremented, and no 500 error is returned"
      },
      {
        "criterion": "Observability metrics are emitted",
        "given": "The rate limiter is running",
        "when": "A request is rate-limited OR Redis is unavailable",
        "then": "rate_limit_exceeded_total or redis_unavailable_total counters are incremented respectively"
      }
    ],
    "terminology_alignment": [
      {
        "domain_term": "rolling window",
        "technical_term": "sliding window via Redis sorted set",
        "definition": "A continuously moving 60-second window where each request's timestamp is tracked individually, as opposed to a fixed-window bucket that resets at discrete intervals"
      },
      {
        "domain_term": "Retry-After",
        "technical_term": "TTL of oldest entry in sorted set",
        "definition": "The number of seconds the client should wait before retrying — dynamically computed as the time until the oldest request in the current window expires (60s - age of oldest request)"
      },
      {
        "domain_term": "fail open",
        "technical_term": "catch-and-allow on Redis exception",
        "definition": "When the rate limiting infrastructure is unavailable, default to allowing requests rather than blocking them — availability over strict enforcement"
      }
    ],
    "contradictions_resolved": [
      {
        "conflict": "MJ proposed a sliding window counter with key pattern rate_limit:{api_key}:{window_start_unix} and 60s TTL per key. Kobe identified this as a fixed-window approach mislabeled as sliding, which allows a burst of up to 200 requests at the boundary between two windows (100 at end of window N, 100 at start of window N+1).",
        "resolution": "Adopted Kobe's recommendation: use Redis sorted sets (ZADD/ZREMRANGEBYSCORE/ZCARD) for a true sliding window. This correctly implements Bird's domain rule of a '60-second rolling window' with no boundary burst. Single key per API key instead of time-bucketed keys."
      },
      {
        "conflict": "MJ's original design implied Retry-After could be derived from the TTL of a fixed-window key. Pippen explicitly stated Retry-After must not be a fixed value.",
        "resolution": "With sorted sets, Retry-After is computed dynamically: 60 minus the age of the oldest request in the set. This satisfies both Pippen's requirement and Bird's AC2."
      }
    ],
    "open_questions": []
  },
  "escalations": [],
  "confidence": {
    "level": 92,
    "high_confidence_areas": [
      "Domain rules are unambiguous and all four agents agree on the 100/60s/rolling semantics",
      "The sorted-set approach is well-established and directly resolves the boundary-burst risk Kobe identified",
      "Fail-open behavior is clearly specified by Pippen and flagged by Kobe as needing explicit tests",
      "Observability requirements are concrete and testable"
    ],
    "low_confidence_areas": [
      "Atomicity of the ZADD+ZREMRANGEBYSCORE+ZCARD sequence under high concurrency — Shaq may need a Lua script to make this atomic",
      "Memory overhead of sorted sets at scale if API keys have very high request volumes — monitor Redis memory"
    ],
    "assumptions": [
      "Redis is already available in the deployment environment (no new infrastructure provisioning needed)",
      "API key is available in the auth context by the time the middleware runs",
      "A single Redis instance or cluster handles the rate limit state (no cross-region considerations)"
    ]
  }
}

